const info = $('Info').first().json;

// Mensagem principal de texto ou transcrição
let mensagem = info.mensagem || $input.first().json.text || '';

if (mensagem.includes('Amara.org')) {
  // Remover transcrição bugada para áudios com silêncio.
  mensagem = '';
}

if (info.mensagem_de_audio) {
  const transcricao = mensagem;
  if (!mensagem) {
    mensagem = '<mensagem de áudio não audível>';
  } else {
    mensagem = `<mensagem-de-audio>${mensagem}</mensagem-de-audio>`
  }
  return { mensagem, transcricao };
}

if (!info.tipo_arquivo) {
  mensagem ||= '<mensagem não suportada. solicitar que usuário envie informação por texto>'
  return { mensagem };
}

if (info.tipo_arquivo === 'image') {
  // Caso adicione análise de imagens, extraia a descrição da imagem e insira aqui.
  let descricaoImagem = '';
  return { mensagem: `${mensagem}\n<usuário enviou uma imagem. peça que envie a informação por áudio ou texto>`.trim(), descricaoImagem };
}

if (info.tipo_arquivo) {
  return { mensagem: `${mensagem}\n<usuário enviou um arquivo do tipo '${info.tipo_arquivo}'>`.trim() };
}

mensagem ||= '<mensagem não suportada. solicitar que usuário envie informação por áudio ou texto>';
return { mensagem: mensagem.trim() };

const ultima_mensagem_da_fila = $input.last();
const mensagem_do_workflow = $('Info').first();

if (ultima_mensagem_da_fila.json.id_mensagem !== mensagem_do_workflow.json.id_mensagem) {
  return [];
}

const vistas = [];
return $input.all().filter(item => {
  if (vistas.includes(item.json.mensagem)) return false;
  vistas.push(item.json.mensagem);
  return true;
});
